import os
from pathlib import Path
import zipfile
import json
import time
from typing import Optional, Dict, Any, List, Tuple

class SimpleFileProcessor:
    """Basic file processor for TXT, JSON, PY, PDF, ZIP files"""

    def __init__(self):
        pass

    def process_file(self, file_path: str) -> Dict[str, Any]:
        file_path_obj = Path(file_path)
        if not file_path_obj.exists():
            return {"error": "File does not exist", "debug_info": {"original_path": file_path, "resolved_path": str(file_path_obj.resolve()), "current_directory": os.getcwd(), "suggestions": ["Check file path", "Verify file permissions"]}}

        file_ext = file_path_obj.suffix.lower()
        content = None
        file_metadata = {
            "filename": file_path_obj.name,
            "size": file_path_obj.stat().st_size,
            "modified_time": file_path_obj.stat().st_mtime
        }

        try:
            if file_ext in ['.txt', '.py', '.json']:
                with open(file_path_obj, 'r', encoding='utf-8') as f:
                    content = f.read()
                file_type = 'text'
                if file_ext == '.json':
                    try:
                        content = json.loads(content)
                        file_type = 'json'
                    except json.JSONDecodeError:
                        file_type = 'text'  # fallback

            elif file_ext == '.pdf' and PDF_AVAILABLE:
                content = self._read_pdf(file_path_obj)
                file_type = 'pdf_file'

            elif file_ext == '.zip':
                extracted_content = self._extract_zip(file_path_obj)
                file_type = 'zip_file'
                return {
                    "type": file_type,
                    "filename": file_path_obj.name,
                    "size": file_path_obj.stat().st_size,
                    "extracted_content": extracted_content,
                    "total_files": len(extracted_content),
                    "file_metadata": file_metadata
                }
            else:
                return {"error": f"Unsupported file type: {file_ext}", "debug_info": {"original_path": file_path, "resolved_path": str(file_path_obj.resolve()), "current_directory": os.getcwd(), "suggestions": ["Add support for this file type", "Convert file to supported format"]}}

        except Exception as e:
            return {"error": f"Failed to read file: {e}", "debug_info": {"original_path": file_path, "resolved_path": str(file_path_obj.resolve()), "current_directory": os.getcwd(), "suggestions": ["Check file integrity", "Verify file permissions"]}}

        return {
            "type": file_type,
            "filename": file_path_obj.name,
            "content": content,
            "size": file_path_obj.stat().st_size,
            "file_metadata": file_metadata
        }

    def _read_pdf(self, file_path: Path) -> str:
        if not PDF_AVAILABLE:
            raise ImportError("PyPDF2 not available")
        content = []
        with open(file_path, 'rb') as f:
            reader = PyPDF2.PdfReader(f)
            for page in reader.pages:
                content.append(page.extract_text() or "")
        return "\n".join(content)

    def _extract_zip(self, file_path: Path) -> Dict[str, Dict[str, Any]]:
        extracted = {}
        with zipfile.ZipFile(file_path, 'r') as zip_ref:
            for info in zip_ref.infolist():
                if info.is_dir():
                    continue
                try:
                    with zip_ref.open(info.filename) as file:
                        file_data = file.read()
                        try:
                            text_content = file_data.decode('utf-8')
                            extracted[info.filename] = {"type": "text", "content": text_content, "size": info.file_size}
                        except UnicodeDecodeError:
                            extracted[info.filename] = {"type": "binary", "content": None, "size": info.file_size}
                except Exception:
                    extracted[info.filename] = {"type": "error", "content": None, "size": info.file_size}
        return extracted

    def list_directory_files(self, directory: str = ".") -> Dict[str, Any]:
        dir_path = Path(directory)
        if not dir_path.exists():
            return {"error": f"Directory not found: {directory}"}
        if not dir_path.is_dir():
            return {"error": f"Path is not a directory: {directory}"}

        files = []
        directories = []
        supported_extensions = {'.txt', '.py', '.json', '.pdf', '.zip'}
        total_files = 0
        supported_files = 0

        try:
            for entry in dir_path.iterdir():
                if entry.is_dir():
                    directories.append({
                        "name": entry.name,
                        "path": str(entry.resolve())
                    })
                elif entry.is_file():
                    total_files += 1
                    ext = entry.suffix.lower()
                    supported = ext in supported_extensions
                    if supported:
                        supported_files += 1
                    files.append({
                        "name": entry.name,
                        "size": entry.stat().st_size,
                        "extension": ext,
                        "supported": supported
                    })
        except Exception as e:
            return {"error": f"Error listing directory: {e}"}

        return {
            "directory": str(dir_path.resolve()),
            "total_files": total_files,
            "supported_files": supported_files,
            "directories": directories,
            "files": files
        }


