class SimpleFileProcessor:
    SUPPORTED_EXTENSIONS = {'.txt', '.py', '.json', '.pdf', '.zip'}

    def process_file(self, file_path: str) -> Dict[str, Any]:
        path = Path(file_path)
        result = {
            "filename": path.name,
            "filepath": str(path),
            "type": None,
            "content": None,
            "file_metadata": {},
            "error": None,
        }

        if not path.exists():
            result["error"] = "File does not exist."
            return result

        if not path.is_file():
            result["error"] = "Path is not a file."
            return result

        ext = path.suffix.lower()
        result["file_metadata"] = {
            "size": path.stat().st_size,
            "created": path.stat().st_ctime,
            "modified": path.stat().st_mtime
        }

        if ext not in self.SUPPORTED_EXTENSIONS:
            result["error"] = f"Unsupported file extension: {ext}"
            return result

        try:
            if ext == '.txt' or ext == '.py' or ext == '.json':
                with path.open('r', encoding='utf-8') as f:
                    content = f.read()
                result["content"] = content
                result["type"] = "text"

            elif ext == '.pdf' and PDF_AVAILABLE:
                with open(file_path, "rb") as f:
                    reader = PyPDF2.PdfReader(f)
                    text = ""
                    for page in reader.pages:
                        text += page.extract_text() or ""
                result["content"] = text
                result["type"] = "pdf_file"

            elif ext == '.zip':
                with zipfile.ZipFile(file_path, 'r') as zip_ref:
                    file_list = zip_ref.namelist()
                    extracted_content = {}
                    for file_name in file_list:
                        if file_name.endswith(tuple(self.SUPPORTED_EXTENSIONS)):
                            with zip_ref.open(file_name) as file:
                                try:
                                    data = file.read()
                                    try:
                                        text = data.decode('utf-8')
                                    except UnicodeDecodeError:
                                        text = repr(data[:200])
                                    extracted_content[file_name] = {
                                        "type": "text",
                                        "content": text,
                                        "size": len(data)
                                    }
                                except Exception:
                                    extracted_content[file_name] = {
                                        "type": "binary",
                                        "content": None,
                                        "size": 0
                                    }
                result["type"] = "zip_file"
                result["total_files"] = len(file_list)
                result["extracted_content"] = extracted_content

            else:
                result["error"] = f"Unsupported file type or missing dependencies for {ext}"
        except Exception as e:
            result["error"] = f"Failed to process file: {e}"

        return result

    def list_directory_files(self, directory: str = ".") -> Dict[str, Any]:
        dir_path = Path(directory)
        if not dir_path.exists() or not dir_path.is_dir():
            return {"error": "Directory does not exist or is not a directory."}

        files = []
        directories = []
        supported_files_count = 0

        for entry in dir_path.iterdir():
            if entry.is_file():
                ext = entry.suffix.lower()
                supported = ext in self.SUPPORTED_EXTENSIONS
                if supported:
                    supported_files_count += 1
                files.append({
                    "name": entry.name,
                    "size": entry.stat().st_size,
                    "extension": ext,
                    "supported": supported
                })
            elif entry.is_dir():
                directories.append({
                    "name": entry.name,
                    "is_empty": len(list(entry.iterdir())) == 0
                })

        return {
            "directory": str(dir_path.resolve()),
            "total_files": len(files),
            "supported_files": supported_files_count,
            "files": sorted(files, key=lambda x: x["name"].lower()),
            "directories": sorted(directories, key=lambda x: x["name"].lower())
        }

